#!/usr/bin/env node
/**
 * Generate a trimmed @garmin/fitsdk Profile.js containing ONLY the message
 * numbers KAIORD's encoder writes and decoder reads. The full Profile.js
 * is ~904 KB / 28K lines (a static dictionary of every FIT message type
 * Garmin has ever defined); KAIORD touches just 9 of them. Vite aliases
 * `@garmin/fitsdk/src/profile.js` → the generated file at SPA build time
 * so rolldown drops ~700 KB of dead dictionary entries from the bundle.
 *
 * Tests (vitest) keep using the real package — vite aliases only affect
 * `pnpm build`, not vitest's standalone config. CI's e2e-frontend +
 * bundle-analysis steps do load the generated file, so any breakage in
 * the trim shows up there.
 *
 * Run: node packages/workout-spa-editor/scripts/generate-fitsdk-minimal.mjs
 *
 * Hooked into the SPA's prebuild step so a stale generated file can never
 * be merged silently if @garmin/fitsdk version bumps.
 */

import { createRequire } from "node:module";
import { writeFile } from "node:fs/promises";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

// Resolve @garmin/fitsdk from packages/fit (the only package that has it
// as a direct dep) so this generator works from any pnpm workspace state.
const require = createRequire(
  fileURLToPath(new URL("../../fit/package.json", import.meta.url))
);
const profileModule = await import(
  require.resolve("@garmin/fitsdk/src/profile.js")
);
const Profile = profileModule.default ?? profileModule.Profile ?? profileModule;

const HERE = dirname(fileURLToPath(import.meta.url));
const PKG = dirname(HERE);
const OUT = join(PKG, "src", "lib", "fitsdk-minimal", "profile.js");

// FIT message numbers KAIORD reads or writes.
// Source of truth: search the codebase for `messages.<key>Mesgs`,
// `fitMessageKeySchema.enum.<key>Mesgs`, and `mesgNum === FIT_MESSAGE_NUMBERS.<X>`.
const KEEP = [
  0, // file_id           — written by encoder, read by every adapter
  18, // session          — read by activity.mapper
  19, // lap              — read by activity.mapper, written by course
  20, // record           — read by activity.mapper, written by course
  21, // event            — read by activity.mapper
  26, // workout          — read by workout.mapper, written by encoder
  27, // workout_step     — read by workout.mapper, written by encoder
  31, // course           — written by course-messages.creator
  32, // course_point     — written by course-messages.creator
];

// Decoder.js inside the SDK references field_description (206) and
// developer_data_id (207) for parsing developer-defined fields. They
// must remain even though KAIORD never reads or writes them at the
// adapter layer, otherwise decoder.js throws when it encounters a
// developer-fields-bearing FIT file in the wild.
const DECODER_REQUIRED = [206, 207];

const allKept = new Set([...KEEP, ...DECODER_REQUIRED]);

const messages = {};
const referencedTypes = new Set();

for (const num of allKept) {
  const msg = Profile.messages?.[num];
  if (!msg) {
    console.error(`Missing message ${num} in source Profile.js`);
    process.exit(1);
  }
  messages[num] = msg;
  for (const f of Object.values(msg.fields ?? {})) {
    if (f.type) referencedTypes.add(f.type);
    for (const sf of f.subFields ?? []) {
      if (sf.type) referencedTypes.add(sf.type);
      for (const m of sf.map ?? []) {
        if (m.refFieldType) referencedTypes.add(m.refFieldType);
      }
    }
  }
}

// Always keep manufacturer (referenced by krd-to-fit-manufacturer.converter.ts)
referencedTypes.add("manufacturer");

const types = {};
for (const t of referencedTypes) {
  if (Profile.types?.[t]) {
    types[t] = Profile.types[t];
  }
}

const minimalProfile = {
  version: Profile.version,
  CommonFields: Profile.CommonFields,
  messages,
  types,
};

const generated = `// This file is auto-generated by scripts/generate-fitsdk-minimal.mjs
// Do NOT edit by hand. Run \`pnpm --filter @kaiord/workout-spa-editor generate:fitsdk-minimal\` to refresh.
// Source: @garmin/fitsdk/src/profile.js v${Profile.version.major}.${Profile.version.minor}.${Profile.version.patch}
// Trimmed to ${Object.keys(messages).length} of ${Object.keys(Profile.messages).length} messages, ${Object.keys(types).length} of ${Object.keys(Profile.types).length} types.

const Profile = ${JSON.stringify(minimalProfile, null, 2)};

export default Profile;
`;

await writeFile(OUT, generated, "utf8");
console.log(
  `Generated ${OUT}: ${Object.keys(messages).length} messages, ${Object.keys(types).length} types`
);
